import React, { useState } from 'react';
import LandingPage from './pages/LandingPage';
import PracticePage from './pages/PracticePage';
import ResultsPage from './pages/ResultsPage';
import DashboardPage from './pages/DashboardPage';
import './App.css';

function App() {
  const [page, setPage] = useState('landing');
  const [analysisData, setAnalysisData] = useState(null);

  const navigate = (newPage, data = null) => {
    setPage(newPage);
    if (data) setAnalysisData(data);
  };

  return (
    <div className="app">
      {page === "landing"   && <LandingPage   navigate={navigate} />}
      {page === "practice"  && <PracticePage  navigate={navigate} />}
    {page === "results" && <ResultsPage results={analysisData} navigate={navigate} />}
      {page === "dashboard" && <DashboardPage navigate={navigate} />}
    </div>
  );
}

export default App;
